from pathlib import Path
import re

path = Path('site/index.html')
text = path.read_text(encoding='utf-8')

replacements = [
    ('view-toggle{display:grid;grid-template-columns:1fr 1fr;gap:6px}', 'view-toggle{display:grid;grid-template-columns:repeat(3,1fr);gap:6px}'),
    ('@media (max-width:980px){body{overflow:auto}#sidebar{position:relative;width:100%;bottom:auto;padding:18px 16px;border-right:0;border-bottom:1px solid var(--line);box-shadow:none}canvas#canvas{position:absolute;left:0;top:0}}', '@media (max-width:980px){body{overflow:auto}#sidebar{position:relative;width:100%;bottom:auto;padding:18px 16px;border-right:0;border-bottom:1px solid var(--line);box-shadow:none}.view-toggle{grid-template-columns:1fr}canvas#canvas{position:absolute;left:0;top:0}}'),
    ('<div class="eyebrow">Canada / StatCan</div>', '<div class="eyebrow">Canada / StatCan / ESDC</div>'),
    ('<button type="button" class="active" data-view="treemap">Treemap</button>\n      <button type="button" data-view="trend">Exposure vs Change</button>', '<button type="button" class="active" data-view="treemap">Treemap</button>\n      <button type="button" data-view="trend">Exposure vs Change</button>\n      <button type="button" data-view="outlook">Exposure vs Outlook</button>'),
    ('<div class="control-copy">Area tracks employment. In treemap view, color tracks AI exposure. In trend view, color tracks employment change since 2019.</div>', '<div class="control-copy" id="viewCopy">Area tracks employment. In treemap view, color tracks AI exposure. In the alternate views, AI exposure stays on the horizontal axis while color shows change or outlook.</div>'),
    ('<div class="stat-section"><h3>High-exposure workers</h3><div class="stat-big" id="statHighExposure">-</div><div class="stat-label" id="statHighExposureDesc">Workers in jobs scored 7+</div></div>\n  <div class="gradient-legend"><span>Low</span><canvas id="gradientLegend" width="80" height="8"></canvas><span>High</span></div>', '<div class="stat-section"><h3>High-exposure workers</h3><div class="stat-big" id="statHighExposure">-</div><div class="stat-label" id="statHighExposureDesc">Workers in jobs scored 7+</div></div>\n  <div class="stat-section"><h3>2025-2027 outlook mix</h3><div class="tier-bar" id="outlookMix"></div></div>\n  <div class="gradient-legend"><span id="legendStart">Low</span><canvas id="gradientLegend" width="80" height="8"></canvas><span id="legendEnd">High</span></div>'),
]

for old, new in replacements:
    if old not in text:
        raise SystemExit(f'missing snippet: {old[:80]!r}')
    text = text.replace(old, new, 1)

insert_after = 'function trendColorCSS(trend,alpha){if(trend==null)return`rgba(128,128,128,${alpha})`;const c=Math.max(-25,Math.min(25,trend));const n=(c+25)/50;let r,g,b;if(n<.5){const s=n/.5;r=Math.round(220-s*55);g=Math.round(72+s*78);b=Math.round(62+s*28)}else{const s=(n-.5)/.5;r=Math.round(165-s*115);g=Math.round(150+s*50);b=Math.round(90-s*30)}return`rgba(${r},${g},${b},${alpha})`}\n'
outlook_fn = 'function outlookColorCSS(score,alpha){if(score==null)return`rgba(128,128,128,${alpha})`;const c=Math.max(-2,Math.min(2,score));const n=(c+2)/4;let r,g,b;if(n<.5){const s=n/.5;r=Math.round(196+s*34);g=Math.round(66+s*118);b=Math.round(56-s*10)}else{const s=(n-.5)/.5;r=Math.round(230-s*56);g=Math.round(184+s*36);b=Math.round(46+s*20)}return`rgba(${r},${g},${b},${alpha})`}\n'
if insert_after not in text:
    raise SystemExit('missing trendColorCSS block')
text = text.replace(insert_after, insert_after + outlook_fn, 1)

const_old = 'const categoryShort={"Management occupations":"Mgmt","Business, finance and administration occupations, except management":"Bus/Admin","Natural and applied sciences and related occupations, except management":"STEM","Health occupations, except management":"Health","Occupations in education, law and social, community and government services, except management":"Edu/Law","Occupations in art, culture, recreation and sport, except management":"Arts","Sales and service occupations, except management":"Sales","Trades, transport and equipment operators and related occupations, except management":"Trades","Natural resources, agriculture and related production occupations, except management":"Resources","Occupations in manufacturing and utilities, except management":"Mfg/Util"};\nconst MOBILE_BREAKPOINT=980,MIN_CANVAS_HEIGHT=560,MARGIN=14,GAP=2,CATEGORY_HEADER=18;let meta={},allData=[],data=[],rects=[],trendRects=[],categoryRects=[],hovered=null,currentView="treemap",activeCategory="All",dpr=window.devicePixelRatio||1;'
const_new = 'const VIEW_INFO={treemap:{colorLine:"color = AI exposure",copy:"Area tracks employment. In treemap view, color tracks AI exposure. In the alternate views, AI exposure stays on the horizontal axis while color shows change or outlook.",legendStart:"Low",legendEnd:"High"},trend:{colorLine:"color = employment change",copy:"Area tracks employment. Columns stay ordered by AI exposure while color shows job growth or contraction since the StatCan baseline year.",legendStart:"Decline",legendEnd:"Growth"},outlook:{colorLine:"color = 2025-2027 outlook",copy:"Area tracks employment. Columns stay ordered by AI exposure while color shows the province-aggregated ESDC outlook for 2025-2027.",legendStart:"Very limited",legendEnd:"Very good"}};\nconst OUTLOOK_LABELS=["Very good","Good","Moderate","Limited","Very limited","Undetermined"];\nconst OUTLOOK_LABEL_TO_SCORE={"Very good":2,"Good":1,"Moderate":0,"Limited":-1,"Very limited":-2};\nconst categoryShort={"Management occupations":"Mgmt","Business, finance and administration occupations, except management":"Bus/Admin","Natural and applied sciences and related occupations, except management":"STEM","Health occupations, except management":"Health","Occupations in education, law and social, community and government services, except management":"Edu/Law","Occupations in art, culture, recreation and sport, except management":"Arts","Sales and service occupations, except management":"Sales","Trades, transport and equipment operators and related occupations, except management":"Trades","Natural resources, agriculture and related production occupations, except management":"Resources","Occupations in manufacturing and utilities, except management":"Mfg/Util"};\nconst MOBILE_BREAKPOINT=980,MIN_CANVAS_HEIGHT=560,MARGIN=14,GAP=2,CATEGORY_HEADER=18;let meta={},allData=[],data=[],rects=[],trendRects=[],outlookRects=[],categoryRects=[],hovered=null,currentView="treemap",activeCategory="All",dpr=window.devicePixelRatio||1;'
if const_old not in text:
    raise SystemExit('missing constants block')
text = text.replace(const_old, const_new, 1)

setview_old = 'function setView(view){currentView=view;document.querySelectorAll("#viewToggle button").forEach(button=>button.classList.toggle("active",button.dataset.view===view));hovered=null;hideTooltip();resize()}'
setview_new = 'function setView(view){currentView=view;document.querySelectorAll("#viewToggle button").forEach(button=>button.classList.toggle("active",button.dataset.view===view));document.getElementById("viewCopy").textContent=VIEW_INFO[view].copy;hovered=null;hideTooltip();drawLegend();updateSubtitle();resize()}'
text = text.replace(setview_old, setview_new, 1)

insert_before = 'function getCanvasPoint(clientX,clientY){const bounds=canvas.getBoundingClientRect();return{x:clientX-bounds.left,y:clientY-bounds.top}}'
outlook_view_fns = 'function layoutOutlook(){const frame=applyCanvasFrame(getCanvasFrame());const pad={top:26,right:10,bottom:32,left:10};const plotW=frame.width-pad.left-pad.right,plotH=frame.height-pad.top-pad.bottom,colGap=3;const byExposure={};let jobsTotal=0;for(const item of data){if(item.exposure==null)continue;if(!byExposure[item.exposure])byExposure[item.exposure]=[];byExposure[item.exposure].push(item);jobsTotal+=item.jobs||0}const scores=Object.keys(byExposure).map(Number).sort((a,b)=>a-b);const colTotals=scores.map(score=>byExposure[score].reduce((sum,item)=>sum+(item.jobs||0),0));const totalGap=colGap*Math.max(0,scores.length-1);const availableW=plotW-totalGap;outlookRects=[];let currentX=pad.left;for(let i=0;i<scores.length;i++){const score=scores[i],items=byExposure[score].slice().sort((a,b)=>(b.outlook_score??-999)-(a.outlook_score??-999)),colJobs=colTotals[i],colW=jobsTotal>0?(colJobs/jobsTotal)*availableW:0;let currentY=pad.top;for(const item of items){const itemH=colJobs>0?((item.jobs||0)/colJobs)*plotH:0;if(itemH<.5){currentY+=itemH;continue}outlookRects.push({...item,rx:currentX,ry:currentY,rw:colW,rh:itemH});currentY+=itemH}currentX+=colW+colGap}outlookRects._meta={pad,plotW,plotH,scores,colTotals,jobsTotal,availableW,colGap}}\nfunction drawOutlook(){ctx.setTransform(dpr,0,0,dpr,0,0);ctx.fillStyle="#07090d";ctx.fillRect(0,0,canvas.width/dpr,canvas.height/dpr);const metaRect=outlookRects._meta;if(!metaRect)return;ctx.textAlign="center";ctx.textBaseline="bottom";ctx.font="600 11px -apple-system,BlinkMacSystemFont,\'Segoe UI\',system-ui,sans-serif";let axisX=metaRect.pad.left;for(let i=0;i<metaRect.scores.length;i++){const colW=metaRect.jobsTotal>0?(metaRect.colTotals[i]/metaRect.jobsTotal)*metaRect.availableW:0;if(colW>14){ctx.fillStyle=exposureColorCSS(metaRect.scores[i],.72);ctx.fillText(metaRect.scores[i],axisX+colW/2,metaRect.pad.top-6)}axisX+=colW+metaRect.colGap}ctx.fillStyle="rgba(255,255,255,.42)";ctx.textBaseline="top";ctx.font="11px -apple-system,BlinkMacSystemFont,\'Segoe UI\',system-ui,sans-serif";ctx.fillText("AI exposure",metaRect.pad.left+metaRect.availableW/2,metaRect.pad.top+metaRect.plotH+8);for(const rect of outlookRects){const isHovered=rect===hovered;const rx=rect.rx+.5,ry=rect.ry+.5,rw=rect.rw-1,rh=rect.rh-1;if(rw<=0||rh<=0)continue;ctx.fillStyle=outlookColorCSS(rect.outlook_score,isHovered?.84:.58);ctx.fillRect(rx,ry,rw,rh);ctx.strokeStyle=isHovered?"#fff":"rgba(255,255,255,.07)";ctx.lineWidth=isHovered?2:1;ctx.strokeRect(rx,ry,rw,rh);if(rw>42&&rh>16){ctx.save();ctx.beginPath();ctx.rect(rx+3,ry+2,rw-6,rh-4);ctx.clip();const fontSize=Math.min(12,Math.max(8,Math.min(rw/12,rh/2.5)));ctx.font=`600 ${fontSize}px -apple-system,BlinkMacSystemFont,\'Segoe UI\',system-ui,sans-serif`;ctx.textAlign="left";ctx.textBaseline="top";ctx.fillStyle=isHovered?"#fff":"rgba(255,255,255,.9)";ctx.fillText(fitText(rect.title,rw-8),rx+4,ry+3);if(rh>28&&rw>56){const info=`${rect.outlook_label||"Undetermined"}  ${formatCompact(rect.jobs)}`;ctx.font=`500 ${Math.max(7,fontSize-2)}px -apple-system,BlinkMacSystemFont,\'Segoe UI\',system-ui,sans-serif`;ctx.fillStyle="rgba(255,255,255,.55)";ctx.fillText(fitText(info,rw-8),rx+4,ry+fontSize+5)}ctx.restore()}}}\n'
outlook_view_fns = outlook_view_fns.replace('isHovered?.84:.58', 'isHovered ? .84 : .58')
if insert_before not in text:
    raise SystemExit('missing insert point for outlook view functions')
text = text.replace(insert_before, outlook_view_fns + insert_before, 1)

compute_re = re.compile(r'function computeStats\(\)\{.*?\}\nfunction drawGradientLegend\(\)\{.*?\}\nfunction updateSubtitle\(\)\{.*?\}\nfunction redraw\(\)\{.*?\}function resize\(\)\{dpr=window.devicePixelRatio\|\|1;redraw\(\)\}', re.S)
compute_new = '''function computeStats(){const visibleJobs=totalJobs(data),nationalJobs=totalJobs(allData),jobsYear=meta.jobs_year||(data[0]?data[0].jobs_year:null),trendFromYear=meta.trend_from_year||(data[0]?data[0].trend_from_year:null),outlookStart=meta.outlook_window_start||(data[0]?data[0].outlook_window_start:null),outlookEnd=meta.outlook_window_end||(data[0]?data[0].outlook_window_end:null);let weightedSum=0,weightedCount=0;for(const item of data){if(item.exposure!=null&&item.jobs){weightedSum+=item.exposure*item.jobs;weightedCount+=item.jobs}}const weightedAvg=weightedCount>0?weightedSum/weightedCount:0;const histogram=new Array(11).fill(0);for(const item of data){if(item.exposure!=null&&item.jobs)histogram[item.exposure]+=item.jobs}const tiers=[{name:"Minimal",range:[0,1],color:exposureColorCSS(.5,1)},{name:"Low",range:[2,3],color:exposureColorCSS(2.5,1)},{name:"Moderate",range:[4,5],color:exposureColorCSS(4.5,1)},{name:"High",range:[6,7],color:exposureColorCSS(6.5,1)},{name:"Very high",range:[8,10],color:exposureColorCSS(9,1)}];for(const tier of tiers){tier.jobs=0;for(const item of data){if(item.exposure!=null&&item.jobs&&item.exposure>=tier.range[0]&&item.exposure<=tier.range[1])tier.jobs+=item.jobs}tier.pct=visibleJobs>0?tier.jobs/visibleJobs*100:0}const maxHist=Math.max(...histogram,0);document.getElementById("statTotalJobs").textContent=formatCompact(visibleJobs);document.getElementById("statTotalJobsDesc").textContent=activeCategory==="All"?(jobsYear?`All families in Canada, ${jobsYear}`:"All families in Canada"):`${shortCategoryLabel(activeCategory)} family, ${nationalJobs>0?(visibleJobs/nationalJobs*100).toFixed(1):"0.0"}% of Canada`;document.getElementById("statAvgExposure").innerHTML=`<span style="color:${exposureColorCSS(weightedAvg,1)}">${weightedAvg.toFixed(1)}</span>`;document.getElementById("histogram").innerHTML=histogram.map((count,score)=>`<div class="bar" style="height:${Math.max(2,maxHist>0?count/maxHist*100:0)}%;background:${exposureColorCSS(score,.78)}" title="${score}: ${formatCompact(count)} workers"></div>`).join("");document.getElementById("tierBar").innerHTML=tiers.map(tier=>`<div class="tier-row"><div class="tier-color" style="background:${tier.color}"></div><span class="tier-name">${tier.name} (${tier.range[0]}-${tier.range[1]})</span><span class="tier-jobs">${formatCompact(tier.jobs)}</span><span class="tier-pct">${tier.pct.toFixed(0)}%</span></div>`).join("");const payBands=[{label:"<$20",min:0,max:20},{label:"$20-30",min:20,max:30},{label:"$30-40",min:30,max:40},{label:"$40-50",min:40,max:50},{label:"$50+",min:50,max:Infinity}];document.getElementById("payChart").innerHTML=payBands.map(band=>{let scoreSum=0,jobsSum=0;for(const item of data){if(item.exposure!=null&&item.jobs&&item.pay_hourly!=null&&item.pay_hourly>=band.min&&item.pay_hourly<band.max){scoreSum+=item.exposure*item.jobs;jobsSum+=item.jobs}}const avg=jobsSum>0?scoreSum/jobsSum:0;return`<div class="hbar-row"><span class="hbar-label">${band.label}</span><div class="hbar-track"><div class="hbar-fill" style="width:${avg/10*100}%;background:${exposureColorCSS(avg,.82)}"></div></div><span class="hbar-val">${avg.toFixed(1)}</span></div>`}).join("");document.getElementById("familyChart").innerHTML=getCategoryGroups(allData).map(group=>`<div class="hbar-row${activeCategory!=="All"&&group.category===activeCategory?" active":""}"><span class="hbar-label">${escapeHTML(group.label)}</span><div class="hbar-track"><div class="hbar-fill" style="width:${group.avg/10*100}%;background:${exposureColorCSS(group.avg,.82)}"></div></div><span class="hbar-val">${group.avg.toFixed(1)}</span></div>`).join("");const highExposureWorkers=data.reduce((sum,item)=>sum+(item.exposure!=null&&item.exposure>=7?(item.jobs||0):0),0);const highExposurePct=visibleJobs>0?highExposureWorkers/visibleJobs*100:0;document.getElementById("statHighExposure").textContent=formatCompact(highExposureWorkers);document.getElementById("statHighExposureDesc").textContent=`${highExposurePct.toFixed(0)}% of visible workers scored 7+${trendFromYear&&jobsYear?`  |  trend view uses ${trendFromYear}-${jobsYear}`:""}`;document.getElementById("outlookMix").innerHTML=OUTLOOK_LABELS.map(label=>{const jobs=data.reduce((sum,item)=>sum+((item.outlook_label||"Undetermined")===label?(item.jobs||0):0),0);const pct=visibleJobs>0?jobs/visibleJobs*100:0;const score=OUTLOOK_LABEL_TO_SCORE[label];const color=label==="Undetermined"?"rgba(140,140,140,.9)":outlookColorCSS(score,.9);return`<div class="tier-row"><div class="tier-color" style="background:${color}"></div><span class="tier-name">${label}</span><span class="tier-jobs">${formatCompact(jobs)}</span><span class="tier-pct">${pct.toFixed(0)}%</span></div>`}).join("")}
function drawLegend(){const legend=document.getElementById("gradientLegend"),gctx=legend.getContext("2d");document.getElementById("legendStart").textContent=VIEW_INFO[currentView].legendStart;document.getElementById("legendEnd").textContent=VIEW_INFO[currentView].legendEnd;for(let x=0;x<legend.width;x++){const t=x/(legend.width-1);if(currentView==="treemap")gctx.fillStyle=exposureColorCSS(t*10,1);else if(currentView==="trend")gctx.fillStyle=trendColorCSS(-25+t*50,1);else gctx.fillStyle=outlookColorCSS(-2+t*4,1);gctx.fillRect(x,0,1,legend.height)}}
function updateSubtitle(){const subtitle=document.getElementById("subtitleMeta"),jobsYear=meta.jobs_year||(data[0]?data[0].jobs_year:""),trendFromYear=meta.trend_from_year||(data[0]?data[0].trend_from_year:""),outlookStart=meta.outlook_window_start||(data[0]?data[0].outlook_window_start:"2025"),outlookEnd=meta.outlook_window_end||(data[0]?data[0].outlook_window_end:"2027"),visibleCount=data.length,totalCount=meta.occupation_count||allData.length||visibleCount,filterLabel=activeCategory==="All"?"All families":shortCategoryLabel(activeCategory),viewInfo=VIEW_INFO[currentView];subtitle.innerHTML=`${visibleCount} of ${totalCount} NOC occupation groups shown | area = employment | ${viewInfo.colorLine}<br>Filter: ${escapeHTML(filterLabel)} | Canada, ${jobsYear} annual data from <a href="https://www150.statcan.gc.ca/t1/tbl1/en/tv.action?pid=1410041601" target="_blank" rel="noopener">StatCan</a><br>Outlook uses province-aggregated ESDC ${outlookStart}-${outlookEnd} data | trend uses ${trendFromYear}-${jobsYear} | <a href="https://karpathy.ai/jobs/" target="_blank" rel="noopener">upstream inspiration</a>`}
function redraw(){if(currentView==="treemap"){layoutTreemap();drawTreemap()}else if(currentView==="trend"){layoutTrend();drawTrend()}else{layoutOutlook();drawOutlook()}}function resize(){dpr=window.devicePixelRatio||1;redraw()}'''
if not compute_re.search(text):
    raise SystemExit('missing compute/legend/update/redraw block')
text = compute_re.sub(compute_new, text, count=1)

text = text.replace('const items=currentView==="treemap"?rects:trendRects;', 'const items=currentView==="treemap"?rects:currentView==="trend"?trendRects:outlookRects;')
text = text.replace('currentView==="treemap"?drawTreemap():drawTrend()', 'currentView==="treemap"?drawTreemap():currentView==="trend"?drawTrend():drawOutlook()')
text = text.replace('tt.querySelector(".tt-stats").innerHTML=`<span class="label">Median hourly wage</span><span class="value">${formatMoney(item.pay_hourly)}</span><span class="label">Workers (${jobsYear||"-"})</span><span class="value">${formatCompact(item.jobs)}</span><span class="label">Employment change</span><span class="value">${formatSignedPercent(item.trend_pct)} (${trendLabel})</span><span class="label">Unemployment</span><span class="value">${formatPercent(item.unemployment_rate)}</span><span class="label">Employment share</span><span class="value">${formatPercent(item.employment_share_pct)}</span>`;', 'const outlookWindow=item.outlook_window_start&&item.outlook_window_end?`${item.outlook_window_start}-${item.outlook_window_end}`:"2025-2027";tt.querySelector(".tt-stats").innerHTML=`<span class="label">Median hourly wage</span><span class="value">${formatMoney(item.pay_hourly)}</span><span class="label">Workers (${jobsYear||"-"})</span><span class="value">${formatCompact(item.jobs)}</span><span class="label">Employment change</span><span class="value">${formatSignedPercent(item.trend_pct)} (${trendLabel})</span><span class="label">Outlook (${outlookWindow})</span><span class="value">${item.outlook_label||"Undetermined"}</span><span class="label">Unemployment</span><span class="value">${formatPercent(item.unemployment_rate)}</span><span class="label">Employment share</span><span class="value">${formatPercent(item.employment_share_pct)}</span>`;')
text = text.replace('fetch("data.json").then(response=>{if(!response.ok)throw new Error(`HTTP ${response.status}`);return response.json()}).then(payload=>{meta=payload.meta||{};allData=payload.occupations||[];data=[...allData];populateCategoryChips();updateSubtitle();computeStats();drawGradientLegend();resize()}).catch(error=>{console.error(error);document.getElementById("subtitleMeta").textContent="Failed to load dashboard data."});', 'fetch("data.json").then(response=>{if(!response.ok)throw new Error(`HTTP ${response.status}`);return response.json()}).then(payload=>{meta=payload.meta||{};allData=payload.occupations||[];data=[...allData];populateCategoryChips();document.getElementById("viewCopy").textContent=VIEW_INFO[currentView].copy;updateSubtitle();computeStats();drawLegend();resize()}).catch(error=>{console.error(error);document.getElementById("subtitleMeta").textContent="Failed to load dashboard data."});')

path.write_text(text, encoding='utf-8')
